1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type Step = { op: string; items?: Array<Item>; policy?: number; incident?: unknown };
4	type Scenario = { customer?: Customer; steps: Array<Step> };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
8	const CURSED_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_YEARS_THRESHOLD = 2;
13	const FOLLOWUP_DISCOUNT_RATE = 0.15;
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	function withFirstInsuranceSurcharge(basePremium: number): number {
25	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
26	}
27	
28	function surchargeIf(condition: boolean, basePremium: number, rate: number): number {
29	  return condition ? basePremium * rate : 0;
30	}
31	
32	function quoteItem(item: Item): number {
33	  const basePremium = BASE_PREMIUMS[item.type];
34	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
35	  const cursedSurcharge = surchargeIf(item.cursed === true, basePremium, CURSED_SURCHARGE_RATE);
36	  const highEnchantmentSurcharge = surchargeIf(
37	    isHighlyEnchanted,
38	    basePremium,
39	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
40	  );
41	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge + highEnchantmentSurcharge;
42	}
43	
44	const COMPONENT_TYPES = ["rune", "moonstone"];
45	const BLOCK_OF_THREE_BASE = 60;
46	
47	function countByType(items: Array<Item>): Record<string, number> {
48	  const counts: Record<string, number> = {};
49	  for (const item of items) {
50	    counts[item.type] = (counts[item.type] ?? 0) + 1;
51	  }
52	  return counts;
53	}
54	
55	function isLoyalCustomer(customer: Customer | undefined): boolean {
56	  return (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
57	}
58	
59	function quoteItems(items: Array<Item>): { itemsPremium: number; sumOfBases: number } {
60	  const counts = countByType(items);
61	  let itemsPremium = 0;
62	  let sumOfBases = 0;
63	  const bundledTypes = new Set<string>();
64	
65	  for (const componentType of COMPONENT_TYPES) {
66	    if (counts[componentType] === 3) {
67	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
68	      sumOfBases += BLOCK_OF_THREE_BASE;
69	      bundledTypes.add(componentType);
70	    }
71	  }
72	
73	  for (const item of items) {
74	    if (bundledTypes.has(item.type)) continue;
75	    itemsPremium += quoteItem(item);
76	    sumOfBases += BASE_PREMIUMS[item.type];
77	  }
78	
79	  return { itemsPremium, sumOfBases };
80	}
81	
82	export function processScenario(
83	  scenario: unknown,
84	): { results: Array<{ premium?: number; payout?: number }> } {
85	  const { customer, steps } = scenario as Scenario;
86	  const results: Array<{ premium?: number; payout?: number }> = [];
87	
88	  for (const [stepIndex, step] of steps.entries()) {
89	    if (step.op === "claim") {
90	      results.push({});
91	      continue;
92	    }
93	
94	    let { itemsPremium, sumOfBases } = quoteItems(step.items ?? []);
95	
96	    if (isLoyalCustomer(customer)) {
97	      itemsPremium -= sumOfBases * LOYALTY_DISCOUNT_RATE;
98	    }
99	
100	    const isFollowUp = stepIndex >= 1;
101	    if (isFollowUp) {
102	      itemsPremium -= sumOfBases * FOLLOWUP_DISCOUNT_RATE;
103	    }
104	
105	    const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
106	    results.push({ premium });
107	  }
108	
109	  return { results };
110	}
