export function processScenario(
  scenario: unknown,
): { results: Array<{ premium?: number; payout?: number; remainingCap?: number }> } {
  const { customer, steps } = scenario as Scenario;
  const results: Array<{ premium?: number; payout?: number; remainingCap?: number }> = [];

  for (const [stepIndex, step] of steps.entries()) {
    if (step.op === "claim") {
      const damages = step.incident?.damages ?? [];
      let payout = 0;
      for (const damage of damages) {
        payout += Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
      }
      results.push({ payout });
      continue;
    }
